import UIKit
import WebKit
import AVFoundation
import UserNotifications
import StoreKit

class WebViewController: UIViewController, WKNavigationDelegate, WKUIDelegate, WKScriptMessageHandler, SKProductsRequestDelegate, SKPaymentTransactionObserver {
    
    var webView: WKWebView!
    var activityIndicator: UIActivityIndicatorView!
    var products: [SKProduct] = []
    var onPurchaseCompletion: ((Bool, String) -> Void)?
    
    override func viewDidLoad() {
        super.viewDidLoad()
        setupWebView()
        setupActivityIndicator()
        loadWebsite()
        SKPaymentQueue.default().add(self)
    }
    
    deinit {
        SKPaymentQueue.default().remove(self)
    }
    
    func setupWebView() {
        let contentController = WKUserContentController()
        contentController.add(self, name: "camera")
        contentController.add(self, name: "pushNotifications")
        contentController.add(self, name: "inAppPurchase")
        contentController.add(self, name: "native")
        
        let config = WKWebViewConfiguration()
        config.userContentController = contentController
        config.preferences.javaScriptEnabled = true
        config.allowsInlineMediaPlayback = true
        config.mediaTypesRequiringUserActionForPlayback = []
        
        webView = WKWebView(frame: .zero, configuration: config)
        webView.navigationDelegate = self
        webView.uiDelegate = self
        webView.translatesAutoresizingMaskIntoConstraints = false
        webView.allowsBackForwardNavigationGestures = true
        
        view.addSubview(webView)
        
        NSLayoutConstraint.activate([
            webView.topAnchor.constraint(equalTo: view.topAnchor),
            webView.bottomAnchor.constraint(equalTo: view.bottomAnchor),
            webView.leadingAnchor.constraint(equalTo: view.leadingAnchor),
            webView.trailingAnchor.constraint(equalTo: view.trailingAnchor)
        ])
    }
    
    func setupActivityIndicator() {
        activityIndicator = UIActivityIndicatorView(style: .large)
        activityIndicator.translatesAutoresizingMaskIntoConstraints = false
        activityIndicator.hidesWhenStopped = true
        view.addSubview(activityIndicator)
        
        NSLayoutConstraint.activate([
            activityIndicator.centerXAnchor.constraint(equalTo: view.centerXAnchor),
            activityIndicator.centerYAnchor.constraint(equalTo: view.centerYAnchor)
        ])
    }
    
    func loadWebsite() {
        guard let url = URL(string: "https://your-mobile-website.com") else { return }
        let request = URLRequest(url: url)
        webView.load(request)
    }
    
    func userContentController(_ userContentController: WKUserContentController, didReceive message: WKScriptMessage) {
        guard let body = message.body as? [String: Any] else { return }
        
        switch message.name {
        case "camera":
            handleCameraRequest(body)
        case "pushNotifications":
            handlePushNotificationRequest(body)
        case "inAppPurchase":
            handleInAppPurchaseRequest(body)
        case "native":
            handleNativeRequest(body)
        default:
            break
        }
    }
    
    func handleCameraRequest(_ data: [String: Any]) {
        guard let action = data["action"] as? String else { return }
        
        switch action {
        case "checkPermission":
            checkCameraPermission()
        case "requestPermission":
            requestCameraPermission()
        case "openCamera":
            openCamera()
        case "openPhotoLibrary":
            openPhotoLibrary()
        default:
            break
        }
    }
    
    func checkCameraPermission() {
        let status = AVCaptureDevice.authorizationStatus(for: .video)
        var permissionStatus = "denied"
        
        switch status {
        case .authorized:
            permissionStatus = "granted"
        case .notDetermined:
            permissionStatus = "notDetermined"
        case .denied, .restricted:
            permissionStatus = "denied"
        @unknown default:
            permissionStatus = "denied"
        }
        
        sendMessageToWeb(event: "cameraPermissionStatus", data: ["status": permissionStatus])
    }
    
    func requestCameraPermission() {
        AVCaptureDevice.requestAccess(for: .video) { [weak self] granted in
            DispatchQueue.main.async {
                self?.sendMessageToWeb(event: "cameraPermissionResult", data: ["granted": granted])
            }
        }
    }
    
    func openCamera() {
        guard UIImagePickerController.isSourceTypeAvailable(.camera) else {
            sendMessageToWeb(event: "cameraError", data: ["error": "Camera not available"])
            return
        }
        
        let picker = UIImagePickerController()
        picker.sourceType = .camera
        picker.delegate = self
        picker.allowsEditing = true
        present(picker, animated: true)
    }
    
    func openPhotoLibrary() {
        let picker = UIImagePickerController()
        picker.sourceType = .photoLibrary
        picker.delegate = self
        picker.allowsEditing = true
        present(picker, animated: true)
    }
    
    func handlePushNotificationRequest(_ data: [String: Any]) {
        guard let action = data["action"] as? String else { return }
        
        switch action {
        case "checkPermission":
            checkNotificationPermission()
        case "requestPermission":
            requestNotificationPermission()
        case "getDeviceToken":
            getDeviceToken()
        default:
            break
        }
    }
    
    func checkNotificationPermission() {
        UNUserNotificationCenter.current().getNotificationSettings { [weak self] settings in
            var status = "denied"
            
            switch settings.authorizationStatus {
            case .authorized, .provisional:
                status = "granted"
            case .notDetermined:
                status = "notDetermined"
            case .denied:
                status = "denied"
            case .ephemeral:
                status = "ephemeral"
            @unknown default:
                status = "denied"
            }
            
            DispatchQueue.main.async {
                self?.sendMessageToWeb(event: "notificationPermissionStatus", data: ["status": status])
            }
        }
    }
    
    func requestNotificationPermission() {
        UNUserNotificationCenter.current().requestAuthorization(options: [.alert, .badge, .sound]) { [weak self] granted, error in
            DispatchQueue.main.async {
                if let error = error {
                    self?.sendMessageToWeb(event: "notificationPermissionResult", data: ["granted": false, "error": error.localizedDescription])
                } else {
                    self?.sendMessageToWeb(event: "notificationPermissionResult", data: ["granted": granted])
                    if granted {
                        UIApplication.shared.registerForRemoteNotifications()
                    }
                }
            }
        }
    }
    
    func getDeviceToken() {
        if let token = UserDefaults.standard.string(forKey: "deviceToken") {
            sendMessageToWeb(event: "deviceToken", data: ["token": token])
        } else {
            sendMessageToWeb(event: "deviceToken", data: ["token": ""])
        }
    }
    
    func handleInAppPurchaseRequest(_ data: [String: Any]) {
        guard let action = data["action"] as? String else { return }
        
        switch action {
        case "getProducts":
            if let productIds = data["productIds"] as? [String] {
                fetchProducts(productIds: productIds)
            }
        case "purchase":
            if let productId = data["productId"] as? String {
                purchaseProduct(productId: productId)
            }
        case "restorePurchases":
            restorePurchases()
        default:
            break
        }
    }
    
    func fetchProducts(productIds: [String]) {
        let request = SKProductsRequest(productIdentifiers: Set(productIds))
        request.delegate = self
        request.start()
    }
    
    func productsRequest(_ request: SKProductsRequest, didReceive response: SKProductsResponse) {
        products = response.products
        
        let productsData = products.map { product -> [String: Any] in
            return [
                "productId": product.productIdentifier,
                "title": product.localizedTitle,
                "description": product.localizedDescription,
                "price": product.price.doubleValue,
                "priceLocale": product.priceLocale.currencyCode ?? "USD"
            ]
        }
        
        sendMessageToWeb(event: "productsLoaded", data: ["products": productsData])
    }
    
    func purchaseProduct(productId: String) {
        guard let product = products.first(where: { $0.productIdentifier == productId }) else {
            sendMessageToWeb(event: "purchaseError", data: ["error": "Product not found"])
            return
        }
        
        let payment = SKPayment(product: product)
        SKPaymentQueue.default().add(payment)
    }
    
    func restorePurchases() {
        SKPaymentQueue.default().restoreCompletedTransactions()
    }
    
    func paymentQueue(_ queue: SKPaymentQueue, updatedTransactions transactions: [SKPaymentTransaction]) {
        for transaction in transactions {
            switch transaction.transactionState {
            case .purchased:
                completePurchase(transaction: transaction)
            case .failed:
                failedPurchase(transaction: transaction)
            case .restored:
                restorePurchase(transaction: transaction)
            case .deferred, .purchasing:
                break
            @unknown default:
                break
            }
        }
    }
    
    func completePurchase(transaction: SKPaymentTransaction) {
        sendMessageToWeb(event: "purchaseSuccess", data: [
            "productId": transaction.payment.productIdentifier,
            "transactionId": transaction.transactionIdentifier ?? ""
        ])
        SKPaymentQueue.default().finishTransaction(transaction)
    }
    
    func failedPurchase(transaction: SKPaymentTransaction) {
        let errorMessage = transaction.error?.localizedDescription ?? "Unknown error"
        sendMessageToWeb(event: "purchaseError", data: [
            "productId": transaction.payment.productIdentifier,
            "error": errorMessage
        ])
        SKPaymentQueue.default().finishTransaction(transaction)
    }
    
    func restorePurchase(transaction: SKPaymentTransaction) {
        sendMessageToWeb(event: "purchaseRestored", data: [
            "productId": transaction.payment.productIdentifier,
            "transactionId": transaction.transactionIdentifier ?? ""
        ])
        SKPaymentQueue.default().finishTransaction(transaction)
    }
    
    func handleNativeRequest(_ data: [String: Any]) {
        guard let action = data["action"] as? String else { return }
        
        switch action {
        case "vibrate":
            UINotificationFeedbackGenerator().notificationOccurred(.success)
        case "share":
            if let text = data["text"] as? String {
                shareContent(text: text, url: data["url"] as? String)
            }
        case "openSettings":
            openAppSettings()
        case "getDeviceInfo":
            sendDeviceInfo()
        default:
            break
        }
    }
    
    func shareContent(text: String, url: String?) {
        var items: [Any] = [text]
        if let urlString = url, let shareURL = URL(string: urlString) {
            items.append(shareURL)
        }
        
        let activityVC = UIActivityViewController(activityItems: items, applicationActivities: nil)
        
        if let popover = activityVC.popoverPresentationController {
            popover.sourceView = view
            popover.sourceRect = CGRect(x: view.bounds.midX, y: view.bounds.midY, width: 0, height: 0)
            popover.permittedArrowDirections = []
        }
        
        present(activityVC, animated: true)
    }
    
    func openAppSettings() {
        if let url = URL(string: UIApplication.openSettingsURLString) {
            UIApplication.shared.open(url)
        }
    }
    
    func sendDeviceInfo() {
        let device = UIDevice.current
        let deviceInfo: [String: Any] = [
            "model": device.model,
            "systemName": device.systemName,
            "systemVersion": device.systemVersion,
            "name": device.name,
            "identifier": device.identifierForVendor?.uuidString ?? ""
        ]
        
        sendMessageToWeb(event: "deviceInfo", data: deviceInfo)
    }
    
    func sendMessageToWeb(event: String, data: [String: Any]) {
        do {
            let jsonData = try JSONSerialization.data(withJSONObject: data, options: [])
            if let jsonString = String(data: jsonData, encoding: .utf8) {
                let script = "window.dispatchEvent(new CustomEvent('\(event)', { detail: \(jsonString) }));"
                webView.evaluateJavaScript(script, completionHandler: nil)
            }
        } catch {
            print("Error serializing data: \(error)")
        }
    }
    
    func webView(_ webView: WKWebView, didStartProvisionalNavigation navigation: WKNavigation!) {
        activityIndicator.startAnimating()
    }
    
    func webView(_ webView: WKWebView, didFinish navigation: WKNavigation!) {
        activityIndicator.stopAnimating()
    }
    
    func webView(_ webView: WKWebView, didFail navigation: WKNavigation!, withError error: Error) {
        activityIndicator.stopAnimating()
    }
    
    func webView(_ webView: WKWebView, createWebViewWith configuration: WKWebViewConfiguration, for navigationAction: WKNavigationAction, windowFeatures: WKWindowFeatures) -> WKWebView? {
        if navigationAction.targetFrame == nil {
            webView.load(navigationAction.request)
        }
        return nil
    }
}

extension WebViewController: UIImagePickerControllerDelegate, UINavigationControllerDelegate {
    func imagePickerController(_ picker: UIImagePickerController, didFinishPickingMediaWithInfo info: [UIImagePickerController.InfoKey : Any]) {
        picker.dismiss(animated: true)
        
        var selectedImage: UIImage?
        if let editedImage = info[.editedImage] as? UIImage {
            selectedImage = editedImage
        } else if let originalImage = info[.originalImage] as? UIImage {
            selectedImage = originalImage
        }
        
        guard let image = selectedImage else {
            sendMessageToWeb(event: "cameraError", data: ["error": "No image selected"])
            return
        }
        
        if let imageData = image.jpegData(compressionQuality: 0.8) {
            let base64String = imageData.base64EncodedString()
            sendMessageToWeb(event: "imageSelected", data: ["image": "data:image/jpeg;base64,\(base64String)"])
        }
    }
    
    func imagePickerControllerDidCancel(_ picker: UIImagePickerController) {
        picker.dismiss(animated: true)
        sendMessageToWeb(event: "cameraCancelled", data: [:])
    }
}